/* ═══ GROQ AI ═══ */
async function callAI(messages, system = "", profile = null, onChunk = null) {
  const profileCtx = profile
    ? `Student: ${profile.grade||""}, goal: ${profile.goal||""}, style: ${profile.style||""}. Adapt tone and depth.`
    : "";
  const sysPrompt = (system || `You are KOS — a brilliant AI study companion. Think clearly, explain beautifully. Use markdown: **bold** key terms, bullet points for lists, numbered steps for processes. Be warm, concise, insightful.`) + "\n\n" + profileCtx;

  const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${GROQ_KEY}` },
    body: JSON.stringify({
      model: "llama-3.3-70b-versatile",
      messages: [{ role: "system", content: sysPrompt }, ...messages],
      temperature: 0.7, max_tokens: 1400, stream: !!onChunk,
    }),
  });
  if (!res.ok) { const e = await res.json(); throw new Error(e.error?.message || "AI error"); }
  if (onChunk) {
    const reader = res.body.getReader(); const decoder = new TextDecoder(); let full = "";
    while (true) {
      const { done, value } = await reader.read(); if (done) break;
      const lines = decoder.decode(value).split("\n").filter(l => l.startsWith("data: ") && !l.includes("[DONE]"));
      for (const line of lines) {
        try { const d = JSON.parse(line.slice(6)); const chunk = d.choices[0]?.delta?.content || ""; full += chunk; onChunk(full); } catch {}
      }
    }
    return full;
  }
  const data = await res.json(); return data.choices[0].message.content;
}

async function callAIJSON(prompt, profile = null) {
  const text = await callAI([{ role: "user", content: prompt }], "Return ONLY valid JSON, no markdown, no explanation.", profile);
  try { return JSON.parse(text.replace(/```json|```/g, "").trim()); }
  catch { throw new Error("Could not parse AI response"); }
}

/* ═══ VISUAL GENERATION ═══ */
function needsVisual(text) {
  const t = text.toLowerCase();
  const STRONG = [
    "diagram","flowchart","flow chart","mind map","mindmap",
    "timeline","venn diagram","draw a","sketch a","chart of",
    "infographic","visualize","show visually","draw me","create a diagram",
    "/visual"
  ];
  return STRONG.some(k => t.includes(k));
}

async function generateVisualImage(userPrompt, aiContext) {
  if (!GEMINI_KEY) return null;
  const structPrompt = `You are a diagram data generator for an educational app called KOS.
Given the topic/request below, produce a JSON object describing a clean educational diagram.
Topic: "${userPrompt}"
Context: "${aiContext.slice(0, 400)}"
Return ONLY valid JSON in one of these formats (pick best fit):
For FLOWCHART:
{"type":"flowchart","title":"...","nodes":[{"id":"1","label":"...","shape":"rect|diamond|oval"},...],"edges":[{"from":"1","to":"2","label":"optional"},...]}
For MINDMAP:
{"type":"mindmap","title":"...","center":"Central Topic","branches":[{"label":"Branch 1","children":["item","item"]},{"label":"Branch 2","children":["item"]},...]}
For TIMELINE:
{"type":"timeline","title":"...","events":[{"year":"...","label":"...","desc":"..."},...]}
For COMPARISON:
{"type":"comparison","title":"...","left":"Option A","right":"Option B","rows":[{"aspect":"...","left":"...","right":"..."},...]}
Rules: Max 7 nodes/events/rows. Labels max 6 words each. No markdown, only JSON`;

  let diagramData = null;
  try {
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_KEY}`,
      { method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ contents: [{ parts: [{ text: structPrompt }] }], generationConfig: { temperature: 0.3, maxOutputTokens: 800 } }) }
    );
    if (!res.ok) return null;
    const data = await res.json();
    const raw = data.candidates?.[0]?.content?.parts?.[0]?.text || "";
    diagramData = JSON.parse(raw.replace(/```json|```/g, "").trim());
  } catch (e) { console.warn("Gemini diagram data failed:", e); return null; }

  try { return await renderDiagramToImage(diagramData); }
  catch (e) { console.warn("Canvas render failed:", e); return null; }
}

async function renderDiagramToImage(data) {
  const W = 680, H = 440;
  const canvas = document.createElement("canvas");
  canvas.width = W * 2; canvas.height = H * 2;
  const ctx = canvas.getContext("2d");
  ctx.scale(2, 2);
  const bg = ctx.createLinearGradient(0, 0, W, H);
  bg.addColorStop(0, "#FAF8F3"); bg.addColorStop(1, "#EEF7F5");
  ctx.fillStyle = bg; ctx.fillRect(0, 0, W, H);
  ctx.strokeStyle = "#2A9D8F0A"; ctx.lineWidth = 1;
  for (let x = 0; x < W; x += 40) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke(); }
  for (let y = 0; y < H; y += 40) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke(); }
  ctx.font = "bold 16px \'Inter\', system-ui, sans-serif"; ctx.fillStyle = "#1C2B2A"; ctx.textAlign = "center";
  ctx.fillText(data.title || "Diagram", W / 2, 32);
  ctx.font = "11px \'Inter\', system-ui, sans-serif"; ctx.fillStyle = "#2A9D8F40"; ctx.textAlign = "right";
  ctx.fillText("Generated by KOS", W - 12, H - 10);
  const helpers = { ctx, W, H };
  if (data.type === "flowchart") await drawFlowchart(data, helpers);
  else if (data.type === "mindmap") await drawMindmap(data, helpers);
  else if (data.type === "timeline") await drawTimeline(data, helpers);
  else if (data.type === "comparison") await drawComparison(data, helpers);
  return canvas.toDataURL("image/png");
}

function drawRoundRect(ctx, x, y, w, h, r, fill, stroke) {
  ctx.beginPath();
  ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y); ctx.arcTo(x + w, y, x + w, y + r, r);
  ctx.lineTo(x + w, y + h - r); ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
  ctx.lineTo(x + r, y + h); ctx.arcTo(x, y + h, x, y + h - r, r);
  ctx.lineTo(x, y + r); ctx.arcTo(x, y, x + r, y, r); ctx.closePath();
  if (fill) { ctx.fillStyle = fill; ctx.fill(); }
  if (stroke) { ctx.strokeStyle = stroke; ctx.lineWidth = 1.5; ctx.stroke(); }
}
function drawArrow(ctx, x1, y1, x2, y2, color = "#2A9D8F") {
  const angle = Math.atan2(y2 - y1, x2 - x1); const headLen = 10;
  ctx.beginPath(); ctx.moveTo(x1, y1); ctx.lineTo(x2, y2);
  ctx.strokeStyle = color; ctx.lineWidth = 1.5; ctx.stroke();
  ctx.beginPath(); ctx.moveTo(x2, y2);
  ctx.lineTo(x2 - headLen * Math.cos(angle - 0.4), y2 - headLen * Math.sin(angle - 0.4));
  ctx.lineTo(x2 - headLen * Math.cos(angle + 0.4), y2 - headLen * Math.sin(angle + 0.4));
  ctx.closePath(); ctx.fillStyle = color; ctx.fill();
}
function wrapText(ctx, text, x, y, maxW, lineH) {
  const words = text.split(" "); let line = ""; const lines = [];
  for (const w of words) {
    const test = line + (line ? " " : "") + w;
    if (ctx.measureText(test).width > maxW && line) { lines.push(line); line = w; } else line = test;
  }
  if (line) lines.push(line);
  const startY = y - ((lines.length - 1) * lineH) / 2;
  lines.forEach((l, i) => ctx.fillText(l, x, startY + i * lineH));
}
async function drawFlowchart(data, { ctx, W, H }) {
  const nodes = data.nodes || []; const edges = data.edges || [];
  if (!nodes.length) return;
  const cols = Math.min(nodes.length, 4); const rows = Math.ceil(nodes.length / cols);
  const cellW = (W - 80) / cols; const cellH = (H - 100) / rows;
  const nodeW = Math.min(cellW - 20, 140); const nodeH = 44;
  const pos = {};
  nodes.forEach((n, i) => { const col = i % cols; const row = Math.floor(i / cols);
    pos[n.id] = { x: 40 + col * cellW + cellW / 2, y: 70 + row * cellH + cellH / 2 }; });
  edges.forEach(e => {
    const a = pos[e.from]; const b = pos[e.to]; if (!a || !b) return;
    drawArrow(ctx, a.x, a.y + nodeH / 2, b.x, b.y - nodeH / 2);
    if (e.label) { ctx.font = "10px \'Inter\', sans-serif"; ctx.fillStyle = "#7A9490"; ctx.textAlign = "center";
      ctx.fillText(e.label, (a.x + b.x) / 2, (a.y + b.y) / 2); }
  });
  nodes.forEach(n => {
    const { x, y } = pos[n.id]; const nx = x - nodeW / 2; const ny = y - nodeH / 2;
    const fill = n.shape === "diamond" ? "#F0ECFF" : n.shape === "oval" ? "#EEF7F5" : "#E8F7F5";
    const stroke = n.shape === "diamond" ? "#6C4FD4" : "#2A9D8F";
    if (n.shape === "diamond") {
      ctx.beginPath(); ctx.moveTo(x, ny); ctx.lineTo(x + nodeW / 2, y);
      ctx.lineTo(x, ny + nodeH); ctx.lineTo(x - nodeW / 2, y);
      ctx.closePath(); ctx.fillStyle = fill; ctx.fill(); ctx.strokeStyle = stroke; ctx.lineWidth = 1.5; ctx.stroke();
    } else if (n.shape === "oval") {
      ctx.beginPath(); ctx.ellipse(x, y, nodeW / 2, nodeH / 2, 0, 0, Math.PI * 2);
      ctx.fillStyle = fill; ctx.fill(); ctx.strokeStyle = stroke; ctx.lineWidth = 1.5; ctx.stroke();
    } else { drawRoundRect(ctx, nx, ny, nodeW, nodeH, 8, fill, stroke); }
    ctx.fillStyle = "#1C2B2A"; ctx.font = "bold 11px \'Inter\', sans-serif"; ctx.textAlign = "center";
    wrapText(ctx, n.label || "", x, y, nodeW - 12, 14);
  });
}
async function drawMindmap(data, { ctx, W, H }) {
  const branches = data.branches || []; const cx = W / 2; const cy = H / 2;
  drawRoundRect(ctx, cx - 70, cy - 22, 140, 44, 12, "#2A9D8F", "#1F7A6E");
  ctx.fillStyle = "#fff"; ctx.font = "bold 13px \'Inter\', sans-serif"; ctx.textAlign = "center";
  wrapText(ctx, data.center || data.title || "Topic", cx, cy, 126, 15);
  const COLORS = ["#2A9D8F","#6C4FD4","#E9C46A","#2ECC8A","#E05454","#4DBDAF","#9B59B6"];
  const angleStep = (Math.PI * 2) / branches.length;
  branches.forEach((branch, bi) => {
    const angle = bi * angleStep - Math.PI / 2;
    const bx = cx + Math.cos(angle) * 140; const by = cy + Math.sin(angle) * 110;
    const color = COLORS[bi % COLORS.length];
    ctx.beginPath(); ctx.moveTo(cx + Math.cos(angle) * 72, cy + Math.sin(angle) * 22);
    ctx.lineTo(bx, by); ctx.strokeStyle = color + "80"; ctx.lineWidth = 2; ctx.stroke();
    drawRoundRect(ctx, bx - 52, by - 16, 104, 32, 8, color + "22", color);
    ctx.fillStyle = color; ctx.font = "bold 11px \'Inter\', sans-serif"; ctx.textAlign = "center";
    ctx.fillText(branch.label || "", bx, by + 4);
    (branch.children || []).forEach((child, ci) => {
      const spread = 0.45; const cAngle = angle + (ci - (branch.children.length - 1) / 2) * spread;
      const childR = 78; const childX = bx + Math.cos(cAngle) * childR; const childY = by + Math.sin(cAngle) * childR;
      ctx.beginPath(); ctx.moveTo(bx, by); ctx.lineTo(childX, childY);
      ctx.strokeStyle = color + "50"; ctx.lineWidth = 1; ctx.stroke();
      drawRoundRect(ctx, childX - 44, childY - 12, 88, 24, 6, "#FFFFFF", color + "60");
      ctx.fillStyle = "#3D5250"; ctx.font = "10px \'Inter\', sans-serif"; ctx.textAlign = "center";
      ctx.fillText(child.slice(0, 14), childX, childY + 4);
    });
  });
}
async function drawTimeline(data, { ctx, W, H }) {
  const events = (data.events || []).slice(0, 7); if (!events.length) return;
  const lineY = H / 2; const margin = 60; const step = (W - margin * 2) / Math.max(events.length - 1, 1);
  const COLORS = ["#2A9D8F","#6C4FD4","#E9C46A","#2ECC8A","#E05454","#4DBDAF","#9B59B6"];
  ctx.beginPath(); ctx.moveTo(margin, lineY); ctx.lineTo(W - margin, lineY);
  ctx.strokeStyle = "#2A9D8F40"; ctx.lineWidth = 2; ctx.stroke();
  events.forEach((ev, i) => {
    const x = margin + i * step; const above = i % 2 === 0; const color = COLORS[i % COLORS.length];
    ctx.beginPath(); ctx.arc(x, lineY, 7, 0, Math.PI * 2); ctx.fillStyle = color; ctx.fill();
    ctx.beginPath(); ctx.arc(x, lineY, 4, 0, Math.PI * 2); ctx.fillStyle = "#fff"; ctx.fill();
    const textY = above ? lineY - 30 : lineY + 30;
    ctx.beginPath(); ctx.moveTo(x, lineY - 7); ctx.lineTo(x, textY + (above ? 16 : -16));
    ctx.strokeStyle = color + "60"; ctx.lineWidth = 1; ctx.stroke();
    drawRoundRect(ctx, x - 24, textY - 12, 48, 20, 5, color, "transparent");
    ctx.fillStyle = "#fff"; ctx.font = "bold 9px \'Inter\', sans-serif"; ctx.textAlign = "center";
    ctx.fillText(ev.year || "", x, textY + 1);
    const labelY = above ? textY - 22 : textY + 28;
    ctx.fillStyle = "#1C2B2A"; ctx.font = "10px \'Inter\', sans-serif";
    wrapText(ctx, ev.label || "", x, labelY, 90, 13);
  });
}
async function drawComparison(data, { ctx, W, H }) {
  const rows = (data.rows || []).slice(0, 6); const colW = (W - 80) / 3;
  const rowH = Math.min((H - 100) / (rows.length + 1), 52); const startY = 60;
  const headers = ["Aspect", data.left || "Option A", data.right || "Option B"];
  const fills = ["#F3F0E8", "#E8F7F5", "#F0ECFF"]; const strokes = ["#C8C2B8", "#2A9D8F", "#6C4FD4"];
  headers.forEach((h, i) => {
    drawRoundRect(ctx, 40 + i * colW, startY, colW - 8, 36, 6, fills[i], strokes[i]);
    ctx.fillStyle = i === 0 ? "#1C2B2A" : strokes[i];
    ctx.font = "bold 12px \'Inter\', sans-serif"; ctx.textAlign = "center";
    ctx.fillText(h, 40 + i * colW + (colW - 8) / 2, startY + 22);
  });
  rows.forEach((row, ri) => {
    const y = startY + 44 + ri * rowH; const rowFills = ["#FAF8F3", "#F5FDFB", "#F8F5FF"];
    [row.aspect, row.left, row.right].forEach((val, ci) => {
      drawRoundRect(ctx, 40 + ci * colW, y, colW - 8, rowH - 6, 5, rowFills[ci], "#E2DDD4");
      ctx.fillStyle = "#3D5250"; ctx.font = "10px \'Inter\', sans-serif"; ctx.textAlign = "center";
      wrapText(ctx, val || "", 40 + ci * colW + (colW - 8) / 2, y + rowH / 2 - 3, colW - 24, 13);
    });
  });
}

/* ═══ VISUAL BLOCK ═══ */
function VisualBlock({ imageDataUrl, title }) {
  const [fullscreen, setFullscreen] = useState(false);
  if (!imageDataUrl) return null;
  const download = () => { const a = document.createElement("a"); a.href = imageDataUrl; a.download = `kos-diagram-${Date.now()}.png`; a.click(); };
  return (
    <>
      {fullscreen && (
        <div onClick={() => setFullscreen(false)} style={{ position: "fixed", inset: 0, background: "rgba(28,43,42,0.85)", backdropFilter: "blur(8px)", zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
          <img src={imageDataUrl} alt={title || "Diagram"} style={{ maxWidth: "100%", maxHeight: "90vh", borderRadius: 16, boxShadow: "0 32px 80px rgba(0,0,0,0.4)" }} />
          <button onClick={() => setFullscreen(false)} style={{ position: "absolute", top: 20, right: 20, width: 40, height: 40, borderRadius: "50%", background: "#fff", border: "none", fontSize: "1.3rem", cursor: "pointer" }}>✕</button>
        </div>
      )}
      <div style={{ marginTop: 14, borderRadius: 16, overflow: "hidden", border: `1.5px solid ${T.teal}25`, boxShadow: `0 4px 24px ${T.teal}10`, background: T.bgCard }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "8px 14px", background: T.tealSoft, borderBottom: `1px solid ${T.teal}15` }}>
          <div style={{ display: "flex", alignItems: "center", gap: 7 }}><span>🎨</span><span style={{ fontSize: "0.8rem", fontWeight: 700, color: T.teal, fontFamily: "Inter, sans-serif" }}>Visual Diagram</span></div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setFullscreen(true)} style={{ fontSize: "0.72rem", background: "none", border: `1px solid ${T.teal}40`, color: T.teal, borderRadius: 8, padding: "3px 10px", cursor: "pointer", fontFamily: "Inter, sans-serif" }}>⛶ Expand</button>
            <button onClick={download} style={{ fontSize: "0.72rem", background: T.teal, border: "none", color: "#fff", borderRadius: 8, padding: "3px 10px", cursor: "pointer", fontFamily: "Inter, sans-serif" }}>↓ Save PNG</button>
          </div>
        </div>
        <div style={{ padding: 16, display: "flex", justifyContent: "center", cursor: "zoom-in" }} onClick={() => setFullscreen(true)}>
          <img src={imageDataUrl} alt={title || "Diagram"} style={{ maxWidth: "100%", borderRadius: 10, boxShadow: T.shadow }} />
        </div>
      </div>
    </>
  );
}

/* ═══ DATABASE ═══ */
const db = {
  async getProfile(id) { try { const { data } = await supabase.from("profiles").select("*").eq("id", id).single(); return data; } catch { return null; } },
  async upsertProfile(id, f) { try { await supabase.from("profiles").upsert({ id, ...f, updated_at: new Date().toISOString() }); } catch(e) { console.warn(e); } },
  async addXP(id, pts) {
    try {
      const { data: p } = await supabase.from("profiles").select("total_xp,streak,last_active").eq("id", id).single();
      const today = new Date().toDateString(); const yesterday = new Date(Date.now()-86400000).toDateString();
      const lastDay = p?.last_active ? new Date(p.last_active).toDateString() : null;
      let streak = p?.streak || 0;
      if (lastDay === yesterday) streak++; else if (lastDay !== today) streak = 1;
      await supabase.from("profiles").update({ total_xp: (p?.total_xp||0)+pts, streak, last_active: new Date().toISOString() }).eq("id", id);
      return { xp: (p?.total_xp||0)+pts, streak };
    } catch { return null; }
  },
  async listChats(uid) { try { const { data } = await supabase.from("chat_sessions").select("id,title,updated_at,messages").eq("user_id", uid).order("updated_at",{ascending:false}).limit(40); return data||[]; } catch { return []; } },
  async createChat(uid) { try { const { data } = await supabase.from("chat_sessions").insert({ user_id:uid, title:"New chat", messages:[] }).select().single(); return data; } catch { return null; } },
  async saveChat(id, msgs, title) {
    const safe = msgs.map(m => ({ role: m.role, content: typeof m.content === "string" ? m.content : (m._display || "[image message]"), ...(m._visual ? { _visual: m._visual } : {}) }));
    try { await supabase.from("chat_sessions").update({ messages: safe, title: title||"Chat", updated_at: new Date().toISOString() }).eq("id", id); } catch {}
  },
  async deleteChat(id) { try { await supabase.from("chat_sessions").delete().eq("id",id); } catch {} },
};

