/* ═══ CONTEXT + REDUCER ═══ */
const Ctx = createContext(null);
function reducer(s, a) {
  switch(a.t) {
    case "SET": return { ...s, ...a.v };
    case "TOAST_ADD": return { ...s, toasts: [...s.toasts, { id: Date.now(), ...a.v }] };
    case "TOAST_DEL": return { ...s, toasts: s.toasts.filter(t => t.id !== a.id) };
    default: return s;
  }
}
function AppProvider({ children }) {
  const [s, d] = useReducer(reducer, { screen: "loading", user: null, profile: null, chats: [], chatId: null, toasts: [], sidebarOpen: false });
  const set = useCallback(v => d({ t: "SET", v }), []);
  const toast = useCallback((msg, type = "success") => {
    const id = Date.now(); d({ t: "TOAST_ADD", v: { msg, type, id } });
    setTimeout(() => d({ t: "TOAST_DEL", id }), 3200);
  }, []);
  useEffect(() => {
    if (!CONFIGURED) { set({ screen: "landing" }); return; }
    let alive = true;
    supabase.auth.getSession().then(({ data }) => {
      if (!alive) return;
      if (data?.session?.user) boot(data.session.user); else set({ screen: "landing" });
    }).catch(() => { if (alive) set({ screen: "landing" }); });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      if (!alive) return;
      if (event === "SIGNED_OUT") set({ user: null, profile: null, screen: "landing" });
      else if (session?.user && (event === "SIGNED_IN" || event === "TOKEN_REFRESHED")) boot(session.user);
    });
    return () => { alive = false; subscription.unsubscribe(); };
  }, []);
  async function boot(user) {
    set({ user });
    let p = await db.getProfile(user.id);
    if (!p) {
      await db.upsertProfile(user.id, { name: user.user_metadata?.full_name || user.email?.split("@")[0] || "Student", email: user.email, avatar_url: user.user_metadata?.avatar_url || "", total_xp: 0, streak: 1, last_active: new Date().toISOString(), onboarding_done: false });
      p = await db.getProfile(user.id);
    }
    set({ profile: p });
    if (!p?.onboarding_done) { set({ screen: "onboarding" }); return; }
    const chats = await db.listChats(user.id);
    set({ screen: "app", chats, chatId: chats[0]?.id || null });
  }
  const addXP = useCallback(async pts => {
    if (!s.user?.id) return;
    const r = await db.addXP(s.user.id, pts);
    if (r) set({ profile: { ...s.profile, total_xp: r.xp, streak: r.streak } });
  }, [s.user?.id, s.profile]);
  return <Ctx.Provider value={{ ...s, set, toast, addXP }}>{children}</Ctx.Provider>;
}
const useApp = () => useContext(Ctx);

/* ═══ MARKDOWN ═══ */
function MdText({ children }) {
  const text = typeof children === "string" ? children : String(children || "");
  const lines = text.split("\n");
  return (
    <div>
      {lines.map((line, i) => {
        if (line.startsWith("### ")) return <div key={i} style={{ fontSize: "1.07rem", fontWeight: 800, color: T.ink, marginTop: 12, marginBottom: 4 }}>{ri(line.slice(4))}</div>;
        if (line.startsWith("## "))  return <div key={i} style={{ fontSize: "1.13rem", fontWeight: 800, color: T.ink, marginTop: 14, marginBottom: 5 }}>{ri(line.slice(3))}</div>;
        if (line.startsWith("# "))   return <div key={i} style={{ fontSize: "1.19rem", fontWeight: 900, color: T.ink, marginTop: 14, marginBottom: 6 }}>{ri(line.slice(2))}</div>;
        if (line.startsWith("- ") || line.startsWith("• ")) return <div key={i} style={{ display: "flex", gap: 8, marginBottom: 4, paddingLeft: 4 }}><span style={{ color: T.teal, flexShrink: 0, fontWeight: 700 }}>·</span><span>{ri(line.slice(2))}</span></div>;
        const nm = line.match(/^(\d+)\. (.*)/);
        if (nm) return <div key={i} style={{ display: "flex", gap: 8, marginBottom: 4, paddingLeft: 4 }}><span style={{ color: T.teal, flexShrink: 0, fontWeight: 700, minWidth: 18 }}>{nm[1]}.</span><span>{ri(nm[2])}</span></div>;
        if (line.startsWith("```") || line.trim() === "") return <div key={i} style={{ height: line.trim() === "" ? 4 : 0 }} />;
        return <div key={i} style={{ marginBottom: 3 }}>{ri(line)}</div>;
      })}
    </div>
  );
}
function ri(text) {
  return text.split(/(\*\*.*?\*\*|`.*?`|\*.*?\*)/g).map((p, i) => {
    if (p.startsWith("**") && p.endsWith("**")) return <strong key={i} style={{ fontWeight: 700 }}>{p.slice(2, -2)}</strong>;
    if (p.startsWith("`") && p.endsWith("`"))   return <code key={i} style={{ background: T.surface, padding: "1px 6px", borderRadius: 5, fontSize: "0.87em", fontFamily: "\'Fira Code\', monospace", color: T.tealDark }}>{p.slice(1, -1)}</code>;
    if (p.startsWith("*") && p.endsWith("*"))   return <em key={i}>{p.slice(1, -1)}</em>;
    return p;
  });
}

