/* ═══ SPLASH ═══ */
function Splash() {
  const canvasRef = useRef(null);
  const [phase, setPhase] = useState("particles");

  useEffect(() => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width = window.innerWidth; const H = canvas.height = window.innerHeight;
    const cx = W / 2; const cy = H / 2;
    const targets = []; const COLS = 8; const ROWS = 8; const SPREAD = 60;
    for (let r = 0; r < ROWS; r++) for (let c = 0; c < COLS; c++)
      targets.push({ tx: cx - (COLS / 2 - 0.5 - c) * (SPREAD / COLS) * 5, ty: cy - (ROWS / 2 - 0.5 - r) * (SPREAD / ROWS) * 5 });
    const COLORS = [T.teal, T.tealLight, T.purple, T.gold, T.tealDark, "#4DBDAF", "#2ECC8A"];
    const particles = targets.map((t, i) => {
      const edge = Math.floor(Math.random() * 4); let sx, sy;
      if (edge === 0) { sx = Math.random() * W; sy = -20; }
      else if (edge === 1) { sx = W + 20; sy = Math.random() * H; }
      else if (edge === 2) { sx = Math.random() * W; sy = H + 20; }
      else { sx = -20; sy = Math.random() * H; }
      return { x: sx, y: sy, sx, sy, tx: t.tx + (Math.random() - 0.5) * 22, ty: t.ty + (Math.random() - 0.5) * 22, size: 2.5 + Math.random() * 4, color: COLORS[i % COLORS.length], delay: Math.random() * 0.35, speed: 0.028 + Math.random() * 0.024, progress: 0, alpha: 1, trail: [] };
    });
    let frame = 0; let animId; let assemblyDone = false;
    function easeInOutCubic(t) { return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2; }
    function draw() {
      ctx.clearRect(0, 0, W, H); ctx.fillStyle = T.bg; ctx.fillRect(0, 0, W, H);
      const grd = ctx.createRadialGradient(cx, cy, 0, cx, cy, 180);
      grd.addColorStop(0, T.teal + "18"); grd.addColorStop(1, "transparent");
      ctx.fillStyle = grd; ctx.fillRect(0, 0, W, H);
      let allArrived = true;
      particles.forEach(p => {
        if (p.progress < 1) { allArrived = false; const effective = Math.max(0, frame / 60 - p.delay); p.progress = Math.min(1, easeInOutCubic(effective * p.speed * 60 * 0.016)); }
        p.x = p.sx + (p.tx - p.sx) * p.progress; p.y = p.sy + (p.ty - p.sy) * p.progress;
        p.trail.push({ x: p.x, y: p.y }); if (p.trail.length > 8) p.trail.shift();
        p.trail.forEach((pt, ti) => { const ta = (ti / p.trail.length) * 0.35 * p.alpha; ctx.beginPath(); ctx.arc(pt.x, pt.y, p.size * (ti / p.trail.length) * 0.6, 0, Math.PI * 2); ctx.fillStyle = p.color + Math.floor(ta * 255).toString(16).padStart(2, "0"); ctx.fill(); });
        ctx.shadowColor = p.color; ctx.shadowBlur = 12 * p.alpha;
        ctx.beginPath(); ctx.arc(p.x, p.y, p.size * p.alpha, 0, Math.PI * 2);
        ctx.fillStyle = p.color + Math.floor(p.alpha * 255).toString(16).padStart(2, "0"); ctx.fill(); ctx.shadowBlur = 0;
      });
      if (allArrived && !assemblyDone) { assemblyDone = true; setTimeout(() => setPhase("logo"), 300); }
      frame++; animId = requestAnimationFrame(draw);
    }
    draw();
    return () => cancelAnimationFrame(animId);
  }, []);

  useEffect(() => { if (phase === "logo") { const t = setTimeout(() => setPhase("done"), 1200); return () => clearTimeout(t); } }, [phase]);

  return (
    <div style={{ height: "100dvh", width: "100vw", position: "relative", overflow: "hidden", background: T.bg }}>
      <canvas ref={canvasRef} style={{ position: "absolute", inset: 0, width: "100%", height: "100%" }} />
      {(phase === "logo" || phase === "done") && (
        <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16, animation: "splashFadeIn 0.8s ease forwards" }}>
          <div style={{ width: 100, height: 100, borderRadius: 30, background: `linear-gradient(145deg, ${T.purpleSoft}, #fff)`, border: `2px solid ${T.purple}30`, display: "flex", alignItems: "center", justifyContent: "center", padding: 14, boxShadow: `0 0 0 12px ${T.purple}12, 0 0 0 24px ${T.purple}06, 0 24px 60px ${T.purple}28`, animation: "splashPulse 2s ease infinite" }}>
            <Logo size={66} />
          </div>
          <div style={{ fontFamily: "\'Playfair Display\', Georgia, serif", fontSize: "2rem", fontWeight: 800, color: T.ink, letterSpacing: "-0.03em", animation: "splashFadeIn 0.6s 0.2s ease both" }}>KOS</div>
          <div style={{ display: "flex", gap: 7, animation: "splashFadeIn 0.6s 0.4s ease both" }}>
            {[0, 1, 2].map(i => <span key={i} style={{ width: 7, height: 7, borderRadius: "50%", background: T.purple, display: "block", animation: `dot 1.3s ${i * 0.18}s ease infinite` }} />)}
          </div>
        </div>
      )}
    </div>
  );
}

