/* ═══ ONBOARDING ═══ */
function Onboarding() {
  const { user, profile, set, toast } = useApp();
  const [step, setStep] = useState(0); const [ans, setAns] = useState({}); const [saving, setSaving] = useState(false);
  const q = ONBOARDING[step];
  const next = async () => {
    if (!ans[q.id]) return;
    if (step < ONBOARDING.length - 1) { setStep(s => s + 1); return; }
    setSaving(true);
    await db.upsertProfile(user.id, { ...ans, onboarding_done: true });
    const chats = await db.listChats(user.id);
    set({ profile: { ...profile, ...ans, onboarding_done: true }, screen: "app", chats, chatId: chats[0]?.id || null });
    toast("Welcome to KOS ✦"); setSaving(false);
  };
  return (
    <div style={{ height: "100dvh", background: T.bg, display: "flex", flexDirection: "column", fontFamily: "Inter, system-ui, sans-serif", paddingTop: "env(safe-area-inset-top)" }}>
      <div style={{ height: 3, background: T.border }}><div style={{ height: "100%", background: T.purple, width: `${((step + 1) / ONBOARDING.length) * 100}%`, transition: "width 0.5s ease", borderRadius: 99 }} /></div>
      <div style={{ flex: 1, padding: "36px 24px 24px", display: "flex", flexDirection: "column" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 40 }}>
          <div style={{ width: 32, height: 32, borderRadius: 10, background: T.purpleSoft, border: `1.5px solid ${T.purple}25`, display: "flex", alignItems: "center", justifyContent: "center", padding: 5 }}><Logo size={20} /></div>
          <div style={{ display: "flex", gap: 5 }}>{ONBOARDING.map((_, i) => <div key={i} style={{ height: 4, borderRadius: 99, width: i === step ? 28 : 14, background: i <= step ? T.purple : T.border, transition: "all 0.4s ease" }} />)}</div>
          <span style={{ fontSize: "0.88rem", color: T.inkLight, marginLeft: "auto" }}>{step + 1}/{ONBOARDING.length}</span>
        </div>
        <h2 style={{ fontSize: "1.86rem", fontWeight: 800, color: T.ink, letterSpacing: "-0.03em", lineHeight: 1.25, marginBottom: 32, fontFamily: "\'Playfair Display\', Georgia, serif" }}>{q.q}</h2>
        <div style={{ display: "flex", flexDirection: "column", gap: 10, flex: 1 }}>
          {q.opts.map(o => (
            <button key={o} onClick={() => setAns(p => ({ ...p, [q.id]: o }))}
              style={{ padding: "17px 20px", borderRadius: 16, textAlign: "left", border: `1.5px solid ${ans[q.id] === o ? T.purple : T.border}`, background: ans[q.id] === o ? T.purpleSoft : T.bgCard, color: ans[q.id] === o ? T.purple : T.inkMid, fontSize: "1.1rem", fontWeight: ans[q.id] === o ? 700 : 400, cursor: "pointer", fontFamily: "Inter, system-ui, sans-serif", display: "flex", justifyContent: "space-between", alignItems: "center", boxShadow: ans[q.id] === o ? `0 4px 20px ${T.purple}18` : T.shadow, transition: "all 0.18s" }}>
              {o}{ans[q.id] === o && <span style={{ color: T.purple, fontSize: "1.24rem" }}>✓</span>}
            </button>
          ))}
        </div>
      </div>
      <div style={{ padding: "16px 24px", paddingBottom: "calc(16px + env(safe-area-inset-bottom))" }}>
        <button onClick={next} disabled={!ans[q.id] || saving}
          style={{ width: "100%", height: 58, borderRadius: 18, border: "none", background: ans[q.id] ? T.purple : T.border, color: ans[q.id] ? "#fff" : T.inkLight, fontSize: "1.13rem", fontWeight: 700, cursor: ans[q.id] && !saving ? "pointer" : "default", fontFamily: "Inter, system-ui, sans-serif", boxShadow: ans[q.id] ? `0 8px 28px ${T.purple}35` : "none", transition: "all 0.2s" }}>
          {saving ? "Setting up…" : step < ONBOARDING.length - 1 ? "Continue →" : "Start Learning ✦"}
        </button>
      </div>
    </div>
  );
}

/* ═══ CHAT APP ═══ */
function ChatApp() {
  const { profile, chats, chatId, set, addXP, toast, sidebarOpen } = useApp();
  const [msgs, setMsgs] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [streaming, setStreaming] = useState("");
  const [slashOpen, setSlashOpen] = useState(false);
  const [recording, setRecording] = useState(false);
  const [savedNotes, setSavedNotes] = useState([]);
  const [showNotes, setShowNotes] = useState(false);
  const [imgPreview, setImgPreview] = useState(null);
  const [imgBase64, setImgBase64] = useState(null);
  const [imgMime, setImgMime] = useState("image/jpeg");
  const [generatingVisual, setGeneratingVisual] = useState(false);
  const mediaRecorderRef = useRef(null);
  const chunksRef = useRef([]);
  const fileInputRef = useRef(null);
  const bottomRef = useRef(null);
  const taRef = useRef(null);

  useEffect(() => {
    if (!chatId || !profile?.id) return;
    const chat = chats.find(c => c.id === chatId);
    if (chat?.messages?.length) setMsgs(chat.messages);
    else supabase.from("chat_sessions").select("messages").eq("id", chatId).single()
      .then(({ data }) => { if (data?.messages) setMsgs(data.messages); else setMsgs([]); });
  }, [chatId]);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [msgs, streaming]);

  const newChat = async () => {
    if (!profile?.id) return;
    const c = await db.createChat(profile.id);
    if (c) { set({ chats: [c, ...chats], chatId: c.id, sidebarOpen: false }); setMsgs([]); }
  };

  const handleInput = e => {
    const v = e.target.value; setInput(v);
    e.target.style.height = "auto"; e.target.style.height = Math.min(e.target.scrollHeight, 160) + "px";
    setSlashOpen(v === "/" || (v.startsWith("/") && !v.includes(" ")));
  };

  const startRecording = async () => {
    if (!navigator.mediaDevices?.getUserMedia) { toast("Microphone not supported", "error"); return; }
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      chunksRef.current = [];
      const mimeType = MediaRecorder.isTypeSupported("audio/webm;codecs=opus") ? "audio/webm;codecs=opus" : MediaRecorder.isTypeSupported("audio/webm") ? "audio/webm" : MediaRecorder.isTypeSupported("audio/mp4") ? "audio/mp4" : "";
      const mr = mimeType ? new MediaRecorder(stream, { mimeType }) : new MediaRecorder(stream);
      mr.ondataavailable = e => { if (e.data.size > 0) chunksRef.current.push(e.data); };
      mr.onstop = async () => {
        const actualType = mr.mimeType || "audio/webm"; const ext = actualType.includes("mp4") ? "m4a" : "webm";
        const blob = new Blob(chunksRef.current, { type: actualType }); stream.getTracks().forEach(t => t.stop());
        if (blob.size < 100) { toast("Recording too short", "error"); setRecording(false); return; }
        try {
          const formData = new FormData(); formData.append("file", blob, `audio.${ext}`); formData.append("model", "whisper-large-v3-turbo"); formData.append("response_format", "text");
          const res = await fetch("https://api.groq.com/openai/v1/audio/transcriptions", { method: "POST", headers: { Authorization: `Bearer ${GROQ_KEY}` }, body: formData });
          if (res.ok) { const text = (await res.text()).trim(); if (text) { setInput(p => p ? p + " " + text : text); taRef.current?.focus(); } else toast("No speech detected", "error"); }
          else { const errData = await res.json().catch(() => ({})); toast(errData?.error?.message || "Voice transcription failed", "error"); }
        } catch (e) { toast("Voice error: " + (e.message || "unknown"), "error"); }
        setRecording(false);
      };
      mediaRecorderRef.current = mr; mr.start(); setRecording(true);
    } catch (e) {
      if (e.name === "NotAllowedError") toast("Microphone access denied", "error");
      else if (e.name === "NotFoundError") toast("No microphone found", "error");
      else toast("Mic error: " + (e.message || "unknown"), "error");
    }
  };
  const stopRecording = () => { try { mediaRecorderRef.current?.stop(); } catch { setRecording(false); } };
  const toggleRecording = () => { recording ? stopRecording() : startRecording(); };

  const handleImageUpload = e => {
    const file = e.target.files[0]; if (!file) return;
    if (!file.type.startsWith("image/")) { toast("Please upload an image file", "error"); return; }
    if (file.size > 4 * 1024 * 1024) { toast("Image too large — max 4MB", "error"); return; }
    const reader = new FileReader();
    reader.onerror = () => toast("Failed to read image", "error");
    reader.onload = ev => { const dataUrl = ev.target.result; setImgPreview(dataUrl); setImgBase64(dataUrl.split(",")[1]); setImgMime(file.type || "image/jpeg"); };
    reader.readAsDataURL(file); e.target.value = "";
  };
  const clearImage = () => { setImgPreview(null); setImgBase64(null); setImgMime("image/jpeg"); };

  const send = async () => {
    if ((!input.trim() && !imgBase64) || loading) return;
    let cid = chatId;
    if (!cid) { const c = await db.createChat(profile.id); if (!c) { toast("Couldn\'t create chat", "error"); return; } set({ chats: [c, ...chats], chatId: c.id }); cid = c.id; }
    const rawInput = input.trim(); const forceVisual = rawInput.toLowerCase().startsWith("/visual");
    const cleanInput = forceVisual ? rawInput.replace(/^\/visual\s*/i, "").trim() || "Explain this concept visually" : rawInput;
    const textContent = cleanInput || (imgBase64 ? "Explain this image:" : "");
    const capturedImg = imgBase64; const capturedMime = imgMime || "image/jpeg";
    const displayText = capturedImg ? `📸 ${textContent || "Explain this image"}` : textContent;
    const userMsg = { role: "user", content: displayText, _display: displayText, ...(capturedImg ? { _imgContent: [{ type: "image_url", image_url: { url: `data:${capturedMime};base64,${capturedImg}` } }, { type: "text", text: textContent || "Explain this image in detail." }] } : {}) };
    const next = [...msgs, userMsg]; setMsgs(next); setInput(""); clearImage(); setLoading(true); setStreaming("");
    if (taRef.current) taRef.current.style.height = "auto";
    try {
      let finalText = "";
      if (capturedImg) {
        if (!GEMINI_KEY) throw new Error("Add VITE_GEMINI_API_KEY to your .env for image analysis");
        const geminiBody = { contents: [{ parts: [{ inline_data: { mime_type: capturedMime, data: capturedImg } }, { text: (textContent || "Explain this image in detail.") + "\n\nYou are KOS, a brilliant AI study companion. Analyse clearly and helpfully. Use markdown: **bold** key terms, bullet points for lists." }] }], generationConfig: { temperature: 0.7, maxOutputTokens: 1400 } };
        const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_KEY}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(geminiBody) });
        if (!res.ok) { const errData = await res.json().catch(() => ({})); const msg = errData?.error?.message || "Image analysis failed"; throw new Error(msg.includes("API_KEY") ? "Invalid Gemini API key — check VITE_GEMINI_API_KEY" : msg); }
        const data = await res.json(); finalText = data.candidates?.[0]?.content?.parts?.[0]?.text || "I couldn\'t analyse that image.";
        const words = finalText.split(" "); let built = "";
        for (const w of words) { built += (built ? " " : "") + w; setStreaming(built); await new Promise(r => setTimeout(r, 16)); }
        setStreaming("");
      } else {
        const cleanMsgs = next.slice(-16).map(m => ({ role: m.role, content: typeof m.content === "string" ? m.content : (m._display || String(m.content || "")) }));
        await callAI(cleanMsgs, "", profile, chunk => { setStreaming(chunk); finalText = chunk; }); setStreaming("");
      }
      const shouldVisual = forceVisual || needsVisual(cleanInput);
      let visualDataUrl = null;
      if (shouldVisual) { setGeneratingVisual(true); try { visualDataUrl = await generateVisualImage(cleanInput, finalText); } catch (e) { console.warn("Visual generation error:", e); } setGeneratingVisual(false); }
      const finalMsg = { role: "assistant", content: finalText, ...(visualDataUrl ? { _visual: visualDataUrl } : {}) };
      const final = [...next, finalMsg]; setMsgs(final);
      let title = chats.find(c => c.id === cid)?.title;
      if (!title || title === "New chat") title = textContent.slice(0, 44);
      await db.saveChat(cid, final, title);
      const updatedChats = await db.listChats(profile.id);
      set({ chats: updatedChats, chatId: cid }); addXP(5);
    } catch (e) {
      toast(e.message || "Something went wrong", "error");
      setMsgs([...next, { role: "assistant", content: "⚠️ " + (e.message || "Something went wrong. Please try again.") }]);
      setStreaming("");
    } finally { setLoading(false); setStreaming(""); setGeneratingVisual(false); }
  };

  const saveNote = content => { const note = { id: Date.now(), content, saved: new Date().toLocaleString() }; setSavedNotes(p => [note, ...p]); toast("Saved to notes 🔖"); };

  const SLASH = [
    { cmd: "/quiz",    icon: "◎",  desc: "Quiz me on any topic" },
    { cmd: "/explain", icon: "💡", desc: "Explain a concept simply" },
    { cmd: "/summary", icon: "≡",  desc: "Summarise text or topic" },
    { cmd: "/flash",   icon: "⚡", desc: "Generate flashcards" },
    { cmd: "/plan",    icon: "→",  desc: "Build a study plan" },
    { cmd: "/essay",   icon: "✒",  desc: "Write or improve an essay" },
    { cmd: "/solve",   icon: "∑",  desc: "Solve a problem step by step" },
    { cmd: "/mindmap", icon: "🗺",  desc: "Create a mind map" },
    { cmd: "/visual",  icon: "🎨", desc: "Generate a visual diagram" },
  ];
  const filteredSlash = SLASH.filter(s => s.cmd.startsWith(input.split(" ")[0]));

  const STARTERS = [
    { icon: "💡", prompt: "Explain ", label: "Explain a concept" },
    { icon: "◎",  prompt: "/quiz ", label: "Quiz me on a topic" },
    { icon: "≡",  prompt: "/summary ", label: "Summarise my notes" },
    { icon: "→",  prompt: "/plan ", label: "Build a study plan" },
    { icon: "🎨", prompt: "/visual ", label: "Generate a diagram" },
    { icon: "✒",  prompt: "/essay ", label: "Help with an essay" },
  ];

  const firstName = profile?.name?.split(" ")[0] || "there";
  const hour = new Date().getHours();
  const greeting = hour < 5 ? "Still up?" : hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : hour < 21 ? "Good evening" : "Studying late?";

  return (
    <div style={{ height: "100dvh", display: "flex", background: T.bg, fontFamily: "Inter, system-ui, sans-serif", position: "relative", overflow: "hidden" }}>
      {sidebarOpen && <div onClick={() => set({ sidebarOpen: false })} style={{ position: "fixed", inset: 0, background: "rgba(28,43,42,0.3)", backdropFilter: "blur(4px)", zIndex: 200 }} />}
      {showNotes && <div onClick={() => setShowNotes(false)} style={{ position: "fixed", inset: 0, background: "rgba(28,43,42,0.3)", backdropFilter: "blur(4px)", zIndex: 200 }} />}

      {/* Notes Panel */}
      <div style={{ position: "fixed", right: 0, top: 0, bottom: 0, width: 300, background: T.bgCard, borderLeft: `1px solid ${T.border}`, display: "flex", flexDirection: "column", transform: showNotes ? "translateX(0)" : "translateX(100%)", transition: "transform 0.28s cubic-bezier(.4,0,.2,1)", zIndex: 300, boxShadow: showNotes ? `-8px 0 40px ${T.tealGlow}` : "none", paddingTop: "env(safe-area-inset-top)" }}>
        <div style={{ padding: "16px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0 }}>
          <div><div style={{ fontWeight: 700, fontSize: "1.13rem", color: T.ink }}>🔖 Saved Notes</div><div style={{ fontSize: "0.79rem", color: T.inkLight, marginTop: 2 }}>{savedNotes.length} saved</div></div>
          <button onClick={() => setShowNotes(false)} style={GBTN}>✕</button>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "10px 12px" }}>
          {savedNotes.length === 0 && <div style={{ textAlign: "center", padding: "40px 16px", color: T.inkLight, fontSize: "0.96rem" }}><div style={{ fontSize: "2.26rem", marginBottom: 10, opacity: 0.2 }}>🔖</div>No saved notes yet.<br />Hit 🔖 on any AI response to save it here.</div>}
          {savedNotes.map(n => (
            <div key={n.id} style={{ padding: "12px 13px", background: T.surface, border: `1px solid ${T.border}`, borderRadius: 14, marginBottom: 9 }}>
              <div style={{ fontSize: "0.93rem", color: T.ink, lineHeight: 1.65, whiteSpace: "pre-wrap", maxHeight: 160, overflow: "hidden" }}>{n.content.slice(0, 280)}{n.content.length > 280 ? "…" : ""}</div>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 8 }}>
                <span style={{ fontSize: "0.73rem", color: T.inkLight }}>{n.saved}</span>
                <div style={{ display: "flex", gap: 8 }}>
                  <button onClick={() => navigator.clipboard.writeText(n.content)} style={{ fontSize: "0.79rem", background: "none", border: "none", color: T.inkLight, cursor: "pointer" }}>Copy</button>
                  <button onClick={() => setSavedNotes(p => p.filter(x => x.id !== n.id))} style={{ fontSize: "0.79rem", background: "none", border: "none", color: T.red, cursor: "pointer" }}>Delete</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Sidebar */}
      <div style={{ position: "fixed", left: 0, top: 0, bottom: 0, width: 282, background: T.bgCard, borderRight: `1px solid ${T.border}`, display: "flex", flexDirection: "column", transform: sidebarOpen ? "translateX(0)" : "translateX(-100%)", transition: "transform 0.28s cubic-bezier(.4,0,.2,1)", zIndex: 300, boxShadow: sidebarOpen ? T.shadowMd : "none", paddingTop: "env(safe-area-inset-top)" }}>
        <div style={{ padding: "16px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 9 }}>
            <div style={{ width: 32, height: 32, borderRadius: 10, background: T.purpleSoft, border: `1.5px solid ${T.purple}25`, display: "flex", alignItems: "center", justifyContent: "center", padding: 5 }}><Logo size={20} /></div>
            <span style={{ fontWeight: 700, fontSize: "1.13rem", color: T.ink, fontFamily: "\'Playfair Display\', serif" }}>KOS</span>
          </div>
          <button onClick={() => set({ sidebarOpen: false })} style={GBTN}>✕</button>
        </div>
        <div style={{ padding: "12px 12px 6px", flexShrink: 0 }}>
          <button onClick={newChat} style={{ width: "100%", padding: "11px 16px", borderRadius: 12, border: `1.5px dashed ${T.purple}40`, background: T.purpleSoft, color: T.purple, fontSize: "0.99rem", fontWeight: 700, cursor: "pointer", fontFamily: "Inter, sans-serif", textAlign: "left", display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontSize: "1.24rem" }}>+</span> New conversation
          </button>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "4px 8px" }}>
          <div style={{ fontSize: "0.72rem", fontWeight: 700, color: T.inkLight, letterSpacing: "0.08em", padding: "8px 8px 5px", textTransform: "uppercase" }}>Conversations</div>
          {chats.map(c => (
            <div key={c.id} style={{ display: "flex", alignItems: "center", gap: 4, borderRadius: 10, marginBottom: 2, background: chatId === c.id ? T.purpleSoft : "transparent", transition: "background 0.15s" }}
              onMouseEnter={e => { if (chatId !== c.id) e.currentTarget.style.background = T.surface; }}
              onMouseLeave={e => { if (chatId !== c.id) e.currentTarget.style.background = "transparent"; }}>
              <button onClick={() => set({ chatId: c.id, sidebarOpen: false })} style={{ flex: 1, padding: "9px 10px", border: "none", textAlign: "left", cursor: "pointer", background: "transparent", color: chatId === c.id ? T.purple : T.inkMid, fontSize: "0.95rem", fontFamily: "Inter, sans-serif", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", display: "flex", alignItems: "center", gap: 7 }}>
                <span style={{ opacity: 0.4, flexShrink: 0, fontSize: "0.85rem" }}>✦</span>
                <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{c.title || "Chat"}</span>
              </button>
              <button onClick={async e => { e.stopPropagation(); await db.deleteChat(c.id); const u = await db.listChats(profile.id); set({ chats: u, chatId: u[0]?.id || null }); }} style={{ background: "none", border: "none", color: T.red, cursor: "pointer", fontSize: "0.88rem", padding: "8px", opacity: 0.3, flexShrink: 0 }}
                onMouseEnter={e => e.currentTarget.style.opacity = "1"}
                onMouseLeave={e => e.currentTarget.style.opacity = "0.3"}>✕</button>
            </div>
          ))}
          {chats.length === 0 && <div style={{ textAlign: "center", padding: "32px 16px", color: T.inkLight, fontSize: "0.95rem" }}>No conversations yet</div>}
        </div>
        <div style={{ padding: "12px 14px", paddingBottom: "calc(12px + env(safe-area-inset-bottom))", borderTop: `1px solid ${T.border}`, flexShrink: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
            <div style={{ width: 36, height: 36, borderRadius: 12, background: `linear-gradient(145deg,${T.purple},#5a3fc0)`, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: "1.13rem", color: "#fff", flexShrink: 0 }}>{(profile?.name || "U")[0].toUpperCase()}</div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: "0.99rem", fontWeight: 700, color: T.ink, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{profile?.name}</div>
              <div style={{ fontSize: "0.77rem", color: T.inkLight }}>⚡ {profile?.total_xp || 0} XP · 🔥 {profile?.streak || 0}d</div>
            </div>
          </div>
          <button onClick={() => supabase.auth.signOut()} style={{ width: "100%", padding: "9px", borderRadius: 10, border: `1px solid ${T.border}`, background: "transparent", color: T.inkLight, fontSize: "0.93rem", cursor: "pointer", fontFamily: "Inter, sans-serif" }}>Sign out</button>
        </div>
      </div>

      {/* Main */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", width: "100%" }}>
        {/* Top bar */}
        <div style={{ height: "calc(54px + env(safe-area-inset-top))", paddingTop: "env(safe-area-inset-top)", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", padding: "0 16px", gap: 12, flexShrink: 0, background: T.bgCard, zIndex: 10, position: "relative" }}>
          <button onClick={() => set({ sidebarOpen: !sidebarOpen })} style={GBTN}>☰</button>
          <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
            <div style={{ width: 30, height: 30, borderRadius: 9, background: T.purpleSoft, border: `1.5px solid ${T.purple}25`, display: "flex", alignItems: "center", justifyContent: "center", padding: 4 }}><Logo size={20} /></div>
            <span style={{ fontSize: "1.07rem", fontWeight: 700, color: T.ink, fontFamily: "\'Playfair Display\', serif" }}>KOS</span>
          </div>
          <button onClick={() => setShowNotes(p => !p)} style={{ ...GBTN, background: savedNotes.length > 0 ? T.purpleSoft : "transparent", color: savedNotes.length > 0 ? T.purple : T.inkLight, border: `1px solid ${savedNotes.length > 0 ? T.purple + "30" : T.border}`, fontSize: "0.93rem", padding: "6px 10px", borderRadius: 10 }}>🔖{savedNotes.length > 0 ? ` ${savedNotes.length}` : ""}</button>
          <button onClick={newChat} style={{ ...GBTN, background: T.purpleSoft, color: T.purple, border: `1px solid ${T.purple}30`, fontSize: "0.9rem", fontWeight: 700, padding: "6px 14px", borderRadius: 10 }}>+ New</button>
        </div>

        {/* Messages */}
        <div style={{ flex: 1, overflowY: "auto", padding: "24px 0 8px" }}>
          <div style={{ maxWidth: 720, width: "100%", margin: "0 auto", padding: "0 16px" }}>
            {msgs.length === 0 && (
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center", paddingTop: 10 }}>
                <div style={{ width: 80, height: 80, borderRadius: 26, background: `linear-gradient(145deg,${T.purpleSoft},#fff)`, border: `2px solid ${T.purple}20`, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 0 0 8px ${T.purple}0D`, padding: 14, marginBottom: 16, animation: "heroFloat 4s ease-in-out infinite" }}>
                  <Logo size={50} />
                </div>
                <h2 style={{ fontSize: "1.64rem", fontWeight: 800, color: T.ink, marginBottom: 6, letterSpacing: "-0.03em", fontFamily: "\'Playfair Display\', serif", textAlign: "center" }}>{greeting}, {firstName} 👋</h2>
                <p style={{ fontSize: "1.02rem", color: T.inkLight, textAlign: "center", lineHeight: 1.7, marginBottom: 30, maxWidth: 300, fontFamily: "Inter, sans-serif" }}>Your Second Brain is ready.<br />Ask me anything.</p>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 9, width: "100%", marginBottom: 18 }}>
                  {STARTERS.map(s => (
                    <button key={s.label} onClick={() => { setInput(s.prompt); taRef.current?.focus(); }}
                      style={{ padding: "13px 14px", borderRadius: 14, border: `1px solid ${T.border}`, background: T.bgCard, textAlign: "left", cursor: "pointer", fontFamily: "Inter, sans-serif", boxShadow: T.shadow, transition: "all 0.15s" }}
                      onMouseEnter={e => { e.currentTarget.style.borderColor = T.purple + "50"; e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = T.shadowMd; }}
                      onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = T.shadow; }}>
                      <div style={{ fontSize: "1.24rem", marginBottom: 5 }}>{s.icon}</div>
                      <div style={{ fontSize: "0.93rem", fontWeight: 600, color: T.inkMid, lineHeight: 1.4 }}>{s.label}</div>
                    </button>
                  ))}
                </div>
                <div style={{ padding: "10px 16px", borderRadius: 12, background: T.surface, border: `1px solid ${T.purple}12`, fontSize: "0.84rem", color: T.inkLight, textAlign: "center", fontFamily: "Inter, sans-serif" }}>
                  💡 Type <strong style={{ color: T.purple }}>/quiz</strong>, <strong style={{ color: T.purple }}>/flash</strong>, <strong style={{ color: T.purple }}>/visual</strong>, <strong style={{ color: T.purple }}>/plan</strong> for AI tools
                </div>
              </div>
            )}
            {msgs.map((m, i) => <Bubble key={i} m={m} onSave={saveNote} />)}
            {streaming && (
              <div style={{ display: "flex", gap: 12, marginBottom: 18, alignItems: "flex-start" }}>
                <div style={{ width: 32, height: 32, borderRadius: 10, flexShrink: 0, background: `linear-gradient(145deg,${T.purple},#5a3fc0)`, display: "flex", alignItems: "center", justifyContent: "center", padding: 5 }}><Logo size={20} style={{ filter: "brightness(0) invert(1)" }} /></div>
                <div style={{ flex: 1, padding: "13px 17px", borderRadius: "4px 18px 18px 18px", background: T.bgCard, border: `1px solid ${T.border}`, fontSize: "1.07rem", lineHeight: 1.8, color: T.ink, boxShadow: T.shadow, fontFamily: "Inter, sans-serif" }}>
                  <MdText>{streaming}</MdText>
                  <span style={{ display: "inline-block", width: 2, height: "1em", background: T.purple, marginLeft: 2, verticalAlign: "text-bottom", animation: "blink 0.8s steps(1) infinite" }} />
                </div>
              </div>
            )}
            {generatingVisual && (
              <div style={{ display: "flex", gap: 12, marginBottom: 18, alignItems: "flex-start" }}>
                <div style={{ width: 32, height: 32, borderRadius: 10, flexShrink: 0, background: `linear-gradient(145deg,${T.purple},#5a3fc0)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1rem" }}>🎨</div>
                <div style={{ padding: "13px 18px", borderRadius: "4px 18px 18px 18px", background: T.bgCard, border: `1px solid ${T.border}`, display: "flex", alignItems: "center", gap: 12, boxShadow: T.shadow, fontFamily: "Inter, sans-serif" }}>
                  <span style={{ animation: "spin 1.2s linear infinite", display: "inline-block", fontSize: "1.1rem" }}>⟳</span>
                  <span style={{ fontSize: "0.95rem", color: T.purple, fontWeight: 600 }}>Drawing your diagram…</span>
                </div>
              </div>
            )}
            {loading && !streaming && !generatingVisual && (
              <div style={{ display: "flex", gap: 12, marginBottom: 18, alignItems: "flex-start" }}>
                <div style={{ width: 32, height: 32, borderRadius: 10, flexShrink: 0, background: `linear-gradient(145deg,${T.purple},#5a3fc0)`, display: "flex", alignItems: "center", justifyContent: "center", padding: 5 }}><Logo size={20} style={{ filter: "brightness(0) invert(1)" }} /></div>
                <div style={{ padding: "13px 18px", borderRadius: "4px 18px 18px 18px", background: T.bgCard, border: `1px solid ${T.border}`, display: "flex", gap: 5, alignItems: "center", boxShadow: T.shadow }}>
                  {[0, 1, 2].map(i => <span key={i} style={{ width: 7, height: 7, borderRadius: "50%", background: T.purple, display: "block", animation: `dot 1.3s ${i * 0.18}s ease infinite` }} />)}
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>
        </div>

        {/* Slash menu */}
        {slashOpen && filteredSlash.length > 0 && (
          <div style={{ position: "absolute", bottom: "calc(80px + env(safe-area-inset-bottom))", left: "50%", transform: "translateX(-50%)", width: "min(680px, calc(100% - 32px))", background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 18, boxShadow: T.shadowMd, overflow: "hidden", zIndex: 50 }}>
            <div style={{ padding: "10px 16px 4px", fontSize: "0.72rem", fontWeight: 700, color: T.inkLight, letterSpacing: "0.08em", textTransform: "uppercase" }}>Commands</div>
            {filteredSlash.map(c => (
              <button key={c.cmd} onClick={() => { setInput(c.cmd + " "); setSlashOpen(false); taRef.current?.focus(); }}
                style={{ width: "100%", display: "flex", gap: 12, alignItems: "center", padding: "11px 16px", border: "none", background: "none", cursor: "pointer", fontFamily: "Inter, sans-serif", textAlign: "left", transition: "background 0.1s" }}
                onMouseEnter={e => e.currentTarget.style.background = T.purpleSoft}
                onMouseLeave={e => e.currentTarget.style.background = "none"}>
                <span style={{ fontSize: "1.13rem", width: 24, textAlign: "center" }}>{c.icon}</span>
                <div><span style={{ fontSize: "1.02rem", fontWeight: 700, color: T.purple }}>{c.cmd}</span><span style={{ fontSize: "0.95rem", color: T.inkMid, marginLeft: 8 }}>{c.desc}</span></div>
              </button>
            ))}
          </div>
        )}

        {/* Image preview */}
        {imgPreview && (
          <div style={{ padding: "8px 16px 0", background: T.bgCard, display: "flex", alignItems: "center", gap: 10, maxWidth: 720, margin: "0 auto", width: "100%" }}>
            <div style={{ position: "relative", display: "inline-flex" }}>
              <img src={imgPreview} alt="preview" style={{ height: 56, width: 56, objectFit: "cover", borderRadius: 10, border: `1px solid ${T.border}` }} />
              <button onClick={clearImage} style={{ position: "absolute", top: -6, right: -6, width: 18, height: 18, borderRadius: "50%", background: T.red, border: "none", color: "#fff", fontSize: "0.68rem", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>✕</button>
            </div>
            <span style={{ fontSize: "0.88rem", color: T.inkLight, fontFamily: "Inter, sans-serif" }}>Image ready — add a question or send as-is</span>
          </div>
        )}

        {/* Input bar */}
        <div style={{ padding: "12px 16px", paddingBottom: "calc(12px + env(safe-area-inset-bottom))", background: T.bgCard, borderTop: `1px solid ${T.border}`, flexShrink: 0 }}>
          <div style={{ maxWidth: 720, margin: "0 auto", display: "flex", gap: 8, alignItems: "flex-end", background: T.bg, border: `1.5px solid ${input ? T.purple + "55" : T.border}`, borderRadius: 22, padding: "10px 10px 10px 18px", boxShadow: input ? `0 0 0 3px ${T.purple}12` : T.shadow, transition: "all 0.2s" }}>
            <textarea ref={taRef} value={input} onChange={handleInput}
              onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); } if (e.key === "Escape") setSlashOpen(false); }}
              placeholder="Ask anything… (type / for commands)"
              rows={1}
              style={{ flex: 1, background: "none", border: "none", outline: "none", resize: "none", color: T.ink, fontSize: "1.1rem", fontFamily: "Inter, sans-serif", lineHeight: 1.65, maxHeight: 160, overflow: "auto", padding: 0 }}
            />
            <button onClick={toggleRecording} title={recording ? "Stop recording" : "Voice input"} style={{ width: 38, height: 38, borderRadius: 12, border: "none", flexShrink: 0, background: recording ? T.red : T.bgAlt, color: recording ? "#fff" : T.inkLight, fontSize: "1.13rem", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.18s", animation: recording ? "micPulse 1s ease infinite" : "none" }}>{recording ? "⏹" : "🎙️"}</button>
            <button onClick={() => fileInputRef.current?.click()} title="Upload image" style={{ width: 38, height: 38, borderRadius: 12, border: "none", flexShrink: 0, background: imgPreview ? T.purpleSoft : T.bgAlt, color: imgPreview ? T.purple : T.inkLight, fontSize: "1.13rem", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.18s" }}>📸</button>
            <input ref={fileInputRef} type="file" accept="image/*" onChange={handleImageUpload} style={{ display: "none" }} />
            <button onClick={send} disabled={(!input.trim() && !imgBase64) || loading} style={{ width: 42, height: 42, borderRadius: 14, border: "none", flexShrink: 0, background: input.trim() && !loading ? T.purple : T.border, color: "#fff", fontSize: "1.3rem", cursor: input.trim() && !loading ? "pointer" : "default", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: input.trim() && !loading ? `0 4px 18px ${T.purple}40` : "none", transition: "all 0.18s" }}>↑</button>
          </div>
          <div style={{ textAlign: "center", fontSize: "0.71rem", color: T.inkLight, marginTop: 7, opacity: 0.5, fontFamily: "Inter, sans-serif" }}>KOS · Your Second Brain, Powered by AI</div>
        </div>
      </div>
    </div>
  );
}

/* ═══ BUBBLE ═══ */
function Bubble({ m, onSave }) {
  const isUser = m.role === "user";
  const [copied, setCopied] = useState(false);
  const safeText = typeof m.content === "string" ? m.content : Array.isArray(m.content) ? (m.content.find(c => c.type === "text")?.text || "[image]") : String(m.content || "");
  const copy = () => { try { navigator.clipboard.writeText(safeText); } catch {} setCopied(true); setTimeout(() => setCopied(false), 1500); };
  return (
    <div style={{ display: "flex", gap: 12, marginBottom: 18, flexDirection: isUser ? "row-reverse" : "row", alignItems: "flex-start" }}>
      {!isUser && (
        <div style={{ width: 32, height: 32, borderRadius: 10, flexShrink: 0, background: `linear-gradient(145deg,${T.purple},#5a3fc0)`, display: "flex", alignItems: "center", justifyContent: "center", padding: 5 }}><Logo size={20} style={{ filter: "brightness(0) invert(1)" }} /></div>
      )}
      <div style={{ maxWidth: "84%", padding: "13px 17px", borderRadius: isUser ? "18px 4px 18px 18px" : "4px 18px 18px 18px", background: isUser ? T.purple : T.bgCard, border: isUser ? "none" : `1px solid ${T.border}`, color: isUser ? "#fff" : T.ink, fontSize: "1.07rem", lineHeight: 1.8, boxShadow: isUser ? `0 4px 18px ${T.purple}30` : T.shadow, fontFamily: "Inter, sans-serif" }}>
        {isUser ? <span style={{ whiteSpace: "pre-wrap" }}>{safeText}</span> : <MdText>{safeText}</MdText>}
        {!isUser && m._visual && <VisualBlock imageDataUrl={m._visual} />}
        {!isUser && (
          <div style={{ display: "flex", gap: 12, marginTop: 8, alignItems: "center" }}>
            <button onClick={copy} style={{ fontSize: "0.77rem", background: "none", border: "none", color: copied ? T.purple : T.inkLight, cursor: "pointer", padding: 0, fontFamily: "Inter, sans-serif", transition: "color 0.2s" }}>{copied ? "Copied ✓" : "Copy ↗"}</button>
            <button onClick={() => { try { onSave && onSave(safeText); } catch {} }} style={{ fontSize: "0.77rem", background: "none", border: "none", color: T.inkLight, cursor: "pointer", padding: 0, fontFamily: "Inter, sans-serif", display: "flex", alignItems: "center", gap: 3 }}>🔖 Save</button>
          </div>
        )}
      </div>
    </div>
  );
}

/* ═══ ROOT ═══ */
export default function App() {
  return (
    <AppProvider>
      <GlobalStyles />
      <Router />
      <ToastLayer />
    </AppProvider>
  );
}

function Router() {
  const { screen } = useApp();
  if (screen === "loading")    return <Splash />;
  if (screen === "landing")    return <Landing />;
  if (screen === "onboarding") return <Onboarding />;
  return <ChatApp />;
}

/* ═══ GLOBAL CSS ═══ */
function GlobalStyles() {
  return (
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;0,800;0,900;1,700;1,800&family=Inter:wght@400;500;600;700&display=swap');
      *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; -webkit-tap-highlight-color: transparent; }
      html { height: 100%; overflow: hidden; -webkit-text-size-adjust: 100%; }
      body { font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #FAF8F3; color: #1C2B2A; height: 100%; overflow: hidden; overscroll-behavior: none; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
      #root { height: 100%; overflow: hidden; }
      button { transition: all 0.15s ease; -webkit-tap-highlight-color: transparent; touch-action: manipulation; }
      button:active:not(:disabled) { transform: scale(0.96); opacity: 0.9; }
      button:disabled { opacity: 0.4; cursor: not-allowed !important; transform: none !important; }
      input, textarea, select { -webkit-appearance: none; appearance: none; font-size: 16px; color-scheme: light; }
      input::placeholder, textarea::placeholder { color: #7A9490; opacity: 0.6; }
      textarea { resize: none; }
      ::-webkit-scrollbar { width: 4px; }
      ::-webkit-scrollbar-thumb { background: #6C4FD430; border-radius: 10px; }
      ::-webkit-scrollbar-track { background: transparent; }
      @keyframes splashFadeIn { from { opacity: 0; transform: scale(0.88) translateY(12px); } to { opacity: 1; transform: scale(1) translateY(0); } }
      @keyframes splashPulse { 0%, 100% { box-shadow: 0 0 0 12px #6C4FD412, 0 0 0 24px #6C4FD406, 0 24px 60px #6C4FD428; } 50% { box-shadow: 0 0 0 20px #6C4FD40D, 0 0 0 36px #6C4FD404, 0 24px 60px #6C4FD438; } }
      @keyframes fadeDown { from { opacity: 0; transform: translateY(-16px); } to { opacity: 1; transform: translateY(0); } }
      @keyframes fadeUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
      @keyframes heroFloat { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }
      @keyframes wordPop { from { opacity: 0; transform: translateY(24px) scale(0.85); } to { opacity: 1; transform: translateY(0) scale(1); } }
      @keyframes cardSlide { from { opacity: 0; transform: translateY(32px) scale(0.94); } to { opacity: 1; transform: translateY(0) scale(1); } }
      @keyframes shimmer { from { left: -100%; } to { left: 200%; } }
      @keyframes marquee { from { transform: translateX(0); } to { transform: translateX(-50%); } }
      @keyframes pulse { 0%, 100% { opacity: 1; transform: scale(1); } 50% { opacity: 0.4; transform: scale(0.8); } }
      @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
      @keyframes slideUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      @keyframes micPulse { 0%, 100% { box-shadow: 0 0 0 0 rgba(224,84,84,0.4); } 50% { box-shadow: 0 0 0 10px rgba(224,84,84,0); } }
      @keyframes dot { 0%, 100% { opacity: 1; transform: translateY(0); } 50% { opacity: 0.3; transform: translateY(-5px); } }
    `}</style>
  );
}